code.C++:
int calculateMinimumBitFlips(int initialNumber, int targetNumber) {
    int x = initialNumber ^ targetNumber;
    return __builtin_popcount(x);
}

code.C:
int calculateMinimumBitFlips(int initialNumber, int targetNumber) {
    int x = initialNumber ^ targetNumber;
    int count = 0;
    while (x) {
        x &= (x - 1);  
        count++;
    }
    return count;
}

code.Java:
public static int calculateMinimumBitFlips(int initialNumber, int targetNumber) {
    return Integer.bitCount(initialNumber ^ targetNumber);
}

code.JavaScript:
function calculateMinimumBitFlips(initialNumber, targetNumber) {
    let x = initialNumber ^ targetNumber;
    let count = 0;
    while (x > 0) {
        x &= (x - 1);
        count++;
    }
    return count;
}
